challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The 'dns' container has exited. This prevents all IMS components (P-CSCF, I-CSCF, S-CSCF, HSS) from performing the DNS lookups required to discover and communicate with each other, causing a total outage of all IMS procedures, including registration.",
      "primary_suspect_nf": "dns",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check the status of all containers, with a focus on 'dns'.",
          "expected_if_hypothesis_holds": "The container 'dns' will be in an 'exited' or 'down' state.",
          "falsifying_observation": "The container 'dns' is in a 'running' state. This would directly contradict the hypothesis."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container='dns'",
          "expected_if_hypothesis_holds": "The tool will either fail (if the container is down) or return an empty list of listeners, confirming no process is listening on the DNS port.",
          "falsifying_observation": "The output shows a process listening on UDP port 53. This would indicate the DNS service is running and listening for requests, falsifying the hypothesis."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "Filter metrics for the 'pcscf' container. Look for metrics related to outbound connection timeouts or DNS resolution failures.",
          "expected_if_hypothesis_holds": "There will be a high or increasing count of client-side SIP transaction timeouts (e.g., kamailio_tm_uac_timeout) or specific DNS failure metrics on the P-CSCF, as it fails to resolve the I-CSCF hostname.",
          "falsifying_observation": "Zero values for DNS failure and client-side timeout metrics on the P-CSCF. This suggests the P-CSCF is successfully resolving and connecting to its upstream hop."
        }
      ],
      "notes": "This plan directly tests the central claim of the hypothesis: the status of the 'dns' container. It then verifies the expected service impact by checking for listening ports and observing client-side metrics on an affected IMS component (P-CSCF)."
    }
  ]
}

